INSERT INTO appearances VALUES(91,13,45,NULL,7.299999999999999823,90,'RM/AMR (right of the attacking band)','Position-representative sample: Rogers'' BEST right-sided outing of 25/26 (8 starts on the right, season avg there 6.33 — his weakest axis). Villa''s brightest player in a 1-3 away defeat.','Right attacking third hottest (att|right 25.9%) but with heavy central drift (mid|centre 22.4%, att|centre 10.3%, def|centre 15.5%) — even his best right-side game is centre-seeking. Full-length coverage x9-97, full width y0-93.','Heat centroid ~x58.4/y39.4 (0-100, y low = right). 58 heat points, 45 touches, 1 key pass, 2 tackles, 90 min. Reading: on the right he keeps leaving the flank to find central touches — the inverse of his left-side game where cutting inside onto his right foot is the WEAPON. Confirms right wing is his weakest deployment.',0,0,'SofaScore API /event/14023994/player/948261 heatmap+statistics (2026-07-02) ; heat_map25 grid from SofaScore API heatmap points (5x5 tool-space, 2026-07-02)','HIGH — measured directly from SofaScore API; representative-sample row for pos_class RM/AMR, selected as his highest-rated right-side start (7.3).','20227044X3007422071100310',60.60000000000000142,58.39999999999999858);
INSERT INTO appearances VALUES(92,14,18,NULL,7.900000000000000355,75,'Left No.8 / deeper left midfielder (pivot-left)','Position-representative sample: Buendía''s deeper LEFT-8 role (8 starts, avg 7.09 — higher than his advanced-left average 6.90). Scored in a 2-0 away win.','Own-half left channel dominant: def|left 31.4% + mid|left 21.6% — real defensive shuttling (4 tackles) — with mid|centre 15.7% circulation and att|centre 9.8% arrivals (his goal). x10-96.','Heat centroid ~x46.4/y68.6 (y high = left). 51 heat points, 36 touches, 75 min, 1 goal. Reading: as a left 8 he does genuine two-way work and still arrives in the box — an underrated deployment that his per-90 numbers say is his most reliable, even if his CEILING games (9.4/8.5/8.3) all came in the advanced left-of-centre free role.',1,0,'SofaScore API /event/14025119/player/783126 heatmap+statistics (2026-07-02) ; heat_map25 grid from SofaScore API heatmap points (5x5 tool-space, 2026-07-02)','HIGH — measured from SofaScore API; representative-sample row for pos_class pivot-left.','021003251126310X431012100',31.39999999999999858,46.39999999999999858);
INSERT INTO appearances VALUES(93,10,3,3,7.900000000000000355,86,'Right-of-centre No.8 (deeper double-pivot right)','Position-representative sample: McGinn''s deeper RIGHT-8 role (7 starts, avg 7.30 — his HIGHEST-average deployment, above his usual RM 7.08). Scored in a 2-0 away win at Feyenoord.','Two-way right-of-centre engine: mid|centre 28.6% + mid|right 22.1% core, def|centre 13% + def|right 11.7% recovery work, att|right 7.8% arrivals. Full length x3-99, full width y0-98.','Heat centroid ~x45.6/y38.9 (y low = right). 77 heat points, 64 touches, 86 min, 1 goal. Reading: dropping McGinn from RM into the right of the pivot trades width for control — highest touch volume and his best average ratings live here, especially in hostile away games.',1,0,'SofaScore API /event/14572642/player/250223 heatmap+statistics (2026-07-02) ; heat_map25 grid from SofaScore API heatmap points (5x5 tool-space, 2026-07-02)','HIGH — measured from SofaScore API; representative-sample row for pos_class pivot-right.','0100113462018X40258103231',61.10000000000000142,45.60000000000000142);
INSERT INTO appearances VALUES(94,10,22,5,7.799999999999999823,67,'Central attacking midfielder (No.10)','Position-representative sample: McGinn as the central 10 (4 starts, avg 6.90). Scored in the 3-0 home win over West Ham.','Central middle third dominant (mid|centre 34.9%) with balanced half-space spread (mid|right 18.6%, mid|left 14%) and box arrivals (att|centre 11.6%, att|left 11.6%). Compact x29-87 — stayed between the lines.','Heat centroid ~x57.9/y47.9 — dead-central connector rather than a roaming creator. 43 heat points, 39 touches, 2 key passes, 67 min, 1 goal. Reading: serviceable central option, but his elite games are wide-right (8.7/8.6) or deep-right (7.9) — the 10 slot spends his pressing/box-crashing on less valuable real estate.',1,0,'SofaScore API /event/14024014/player/250223 heatmap+statistics (2026-07-02) ; heat_map25 grid from SofaScore API heatmap points (5x5 tool-space, 2026-07-02)','HIGH — measured from SofaScore API; representative-sample row for pos_class CAM.','110014165153X550031100000',52.10000000000000142,57.89999999999999858);
INSERT INTO appearances VALUES(95,9,41,4,7.900000000000000355,90,'Free No.10 (left-leaning)','Position-representative sample: Tielemans as the advanced free 10 (7 starts, avg 7.24, best 8.4). Assisted in the 3-1 home win over Forest.','Enormous-volume tempo control: mid|centre 25.7% + mid|left 22.8% + att|left 16.9% — a left-leaning 10 who also switches to att|right (11.8%). Full pitch x10-99, y3-99.','Heat centroid ~x59.2/y59.2. 136 heat points and 123 TOUCHES in 90 min — nearly double a normal 10''s volume; 1 assist, 4 tackles. Reading: as a 10 he is a deep-connecting metronome, not a penalty-box creator; the volume migrates toward the ball. His deep-pivot average (7.32 over 11 starts) still edges this, and his single best games (8.4 EL final) came deeper.',0,1,'SofaScore API /event/14025276/player/331737 heatmap+statistics (2026-07-02) ; heat_map25 grid from SofaScore API heatmap points (5x5 tool-space, 2026-07-02)','HIGH — measured from SofaScore API; representative-sample row for pos_class CAM.','320116X792396211332001100',40.79999999999999715,59.20000000000000284);
INSERT INTO appearances VALUES(96,8,18,NULL,7.299999999999999823,89,'Right-of-centre double pivot','Position-representative sample: Onana on the RIGHT of the pivot (8 starts, avg 7.04) — mirror-side proof of his side-flexibility (15 centre starts avg 7.21, 6 left avg 7.05).','Right-of-centre midfield block: mid|right 34.5% core with mid|centre 17.2% + def|centre 15.5% screening and att|right 12.1% surges. x3-91, y0-83.','Heat centroid ~x46.1/y38.4 (y low = right). 58 heat points, 46 touches, 89 min, 3 tackles, 1 key pass. Reading: Onana''s footprint is side-agnostic — he takes whichever pivot side his partner does not (left of Kamara, right of Tielemans), with near-identical output on all three lanes.',0,0,'SofaScore API /event/14025119/player/923973 heatmap+statistics (2026-07-02) ; heat_map25 grid from SofaScore API heatmap points (5x5 tool-space, 2026-07-02)','HIGH — measured from SofaScore API; representative-sample row for pos_class pivot-right.','0010000055206X11242201220',61.60000000000000142,46.10000000000000142);
