INSERT INTO appearances VALUES(139,13,53,NULL,5.799999999999999823,90,'RM/AMR — right of the attacking three in the 4-2-3-1 (Tielemans No.10 y=45.6, Ramsey left y=73.6, Rogers y=38.7)','24/25 sample #1 (Arsenal away, MW22 2-2). Off-ball two-way shuttle on the right; heavy defensive shift, minimal on-ball impact.','def-right 23.9%, mid-left 17.4%, mid-right 17.4%, mid-centre 10.9%, def-centre 8.7%, att-right 8.7%, att-centre 6.5%, att-left 4.3%, def-left 2.2% (x-thirds × y-thirds, 46 points)','Nominal right attacker but pinned into his own half: centroid (44.4, 38.2), hottest zone def-right 23.9% — doubling with Cash against Arsenal''s left (Martinelli/Calafiori side). Full-length x range 5–97 with cross-lane drift into mid-left 17.4% when Villa broke out. On-ball involvement very low for 90 min: 29 touches, 16 passes at 50%, 3/15 duels won, 5 fouls, 3 dispossessed, 1 key pass (xA 0.03), 0 shots → rating 5.8 (alt 6.2). A defensive-workload right-side performance, not a creative one.',0,0,'SofaScore API /event/12436443/player/948261 heatmap+statistics, /event/12436443/lineups, /event/12436443/average-positions (2026-07-02); 46 heat points, 29 touches','HIGH — rating/minutes/heatmap/avg coords are SofaScore API official values; slot ID HIGH via lineup + avg-positions cross-check (Rogers y=38.7 right vs Ramsey 73.6 left)','000035350604434030050043X',61.79999999999999716,44.39999999999999858);
